{"path": "/tmp/sv-8e3169a5e88946a3867e6ce20028640c/Components/Pages/Catalog/CatalogSidebar.razor", "file_text": "<div class="p-3 border rounded">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@(_selectedCategories.Contains(category))"
                           @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2">
            <input type="number" class="form-control" placeholder="Min"
                   value="@_minPrice"
                   @onchange="e => _minPrice = ParseDecimal(e.Value)" />
            <input type="number" class="form-control" placeholder="Max"
                   value="@_maxPrice"
                   @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
        </div>
    </div>

    <div class="mb-3 form-check">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly"
               @onchange="e => _inStockOnly = (bool)e.Value!" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = new();

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    [Parameter]
    public EventCallback OnFiltersCleared { get; set; }

    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFiltersCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

